def is_valid_parentheses(s: str) -> bool:
    matching_open = {')': '(', ']': '[', '}': '{'}
    openers = set(matching_open.values())
    pending = []

    for ch in s:
        if ch in openers:
            pending.append(ch)
        else:
            if not pending or pending[-1] != matching_open[ch]:
                return False
            pending.pop()

    return len(pending) == 0


if __name__ == "__main__":
    examples = ["()", "()[]{}", "(]", "([])", "([)]"]
    for example in examples:
        print(example, is_valid_parentheses(example))
